#include <bits/stdc++.h>
#define int long long
using namespace std;
const int N = 1e5 + 1;
int n, k, cnt, Head[N];
int a[N], d[N][21], f[N][21];
struct Edge {
	int nxt, to;
} edge[N << 1];
void ins (int x, int y) {
	edge[++cnt].nxt = Head[x];
	edge[cnt].to = y;
	Head[x] = cnt;
}
void dfs (int x, int fa, int u) {
	d[x][u] += a[x];
	for (int i = Head[x]; i; i = edge[i].nxt) {
		int y = edge[i].to;
		if (y == fa) {
			continue;
		}
		d[x][u] += d[y][u - 1];
		dfs (y, x, u);
	}
	return;
}
void calc (int x, int fa, int u) {
	int w;
	if (u - 2 >= 0) {
		w = d[x][u - 2];
	}  else {
		w = 0;
	}
	f[x][u] = f[fa][u - 1] - w + d[x][u];
	for (int i = Head[x]; i; i = edge[i].nxt) {
		if (edge[i].to != fa) {
			calc (edge[i].to, x, u);
		}
	}
	return;
}
void work (int u) {
	for (int i = Head[1]; i; i = edge[i].nxt) {
		calc (edge[i].to, 1, u);
	}
	return;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n >> k;
	for (int i = 1, x, y; i < n; i++) {
		cin >> x >> y;
		ins (x, y);
		ins (y, x);
	}
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
		d[i][0] = a[i];
	}
	if (!k) {
		for (int i = 1; i <= n; i++) {
			cout << a[i] << '\n';
		}
		return 0;
	}
	for (int i = 1; i <= k; i++) {
		dfs (1, 0, i);
		f[1][i] = d[1][i];
	}
	for (int i = 1; i <= n; i++) {
		f[i][0] = a[i];
	}
	for (int i = 1; i <= k; i++) {
		work (i);
	}
	for (int i = 1; i <= n; i++) {
		cout << f[i][k] << '\n';
	}
	return 0;
}
